local function is_safe_path(base, path)
    local full_path = base .. '/' .. path
    local resolved_base = ngx.re.gsub(ngx.re.gsub(base, "/$", ""), "/+", "/")
    local resolved_path = ngx.re.gsub(ngx.re.gsub(full_path, "/+", "/"), "/$", "")
    return ngx.re.match(resolved_path, "^" .. ngx.re.escape(resolved_base))
end

local function serve_file()
    local args = ngx.req.get_uri_args()
    local filename = args.filename

    if not filename then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say("Filename is required")
        return
    end

    local base_dir = "./files"
    if not is_safe_path(base_dir, filename) then
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.say("Access denied")
        return
    end

    local file_path = base_dir .. '/' .. filename
    local file, err = io.open(file_path, "rb")

    if not file then
        ngx.status = ngx.HTTP_NOT_FOUND
        ngx.say("File not found: ", err)
        return
    end

    ngx.header.content_type = "text/plain"
    ngx.say(file:read("*a"))
    file:close()
end

serve_file()